@app.route('/saml/sso', methods=['GET', 'POST'])
def sso():
    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest', '')
        relay_state = request.args.get('RelayState', '')
        
        return render_template_string(LOGIN_TEMPLATE, 
                                     saml_request=saml_request, 
                                     relay_state=relay_state,
                                     error=None)
    
    else:  # POST
        username = request.form.get('username')
        password = request.form.get('password')
        saml_request = request.form.get('SAMLRequest', '')
        relay_state = request.form.get('RelayState', '')
        
        # Authenticate user
        if username not in USERS or USERS[username]['password'] != password:
            return render_template_string(LOGIN_TEMPLATE, 
                                         saml_request=saml_request, 
                                         relay_state=relay_state,
                                         error="Invalid credentials")
        
        user_attributes = USERS[username]['attributes']
        
        # Parse SAMLRequest if present
        in_response_to = None
        sp_acs_url = None
        sp_entity_id = None
        
        if saml_request:
            try:
                decoded_request = base64.b64decode(saml_request)
                xml_tree = etree.fromstring(decoded_request)
                
                in_response_to = xml_tree.get('ID')
                sp_acs_url = xml_tree.get('AssertionConsumerServiceURL')
                
                issuer_elem = xml_tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
                if issuer_elem is not None:
                    sp_entity_id = issuer_elem.text
            except:
                pass
        
        # Use defaults if not in SAMLRequest
        if not sp_acs_url:
            sp_acs_url = request.args.get('acs_url', 'https://sp.example.com/saml/acs')
        if not sp_entity_id:
            sp_entity_id = request.args.get('sp_entity_id', 'https://sp.example.com/saml/metadata')
        
        # Generate SAML response
        saml_response = idp.generate_saml_response(
            user_attributes=user_attributes,
            sp_acs_url=sp_acs_url,
            sp_entity_id=sp_entity_id,
            in_response_to=in_response_to
        )
        
        # Return POST form to send to SP
        return render_template_string(POST_TEMPLATE,
                                     acs_url=sp_acs_url,
                                     saml_response=saml_response,
                                     relay_state=relay_state)


